vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    // Precompute popcount-depth for each number in nums
    vector<long long> popcount_depths;
    for (long long num : nums) {
        long long x = num;
        long long d = 0;
        while (x > 0) {
            x = __builtin_popcount(x);
            d++;
        }
        popcount_depths.push_back(d);
    }

    // Create a 2D array to store the frequency of each popcount-depth
    // Since k can be up to 5, we can use a 2D array of size n x 6
    vector<vector<long long>> freq(nums.size(), vector<long long>(6, 0));
    for (int i = 0; i < nums.size(); ++i) {
        freq[i][popcount_depths[i]]++;
    }

    // For each query, process it
    vector<long long> answer;
    for (vector<long long> query : queries) {
        if (query[0] == 1) {
            // Type 1 query: count numbers in [l, r] with popcount-depth k
            long long l = query[1], r = query[2], k = query[3];
            long long count = 0;
            for (int i = l; i <= r; ++i) {
                if (freq[i][k] > 0) {
                    count++;
                }
            }
            answer.push_back(count);
        } else {
            // Type 2 query: update nums[idx] to val
            long long idx = query[1], val = query[2];
            // Update the value in nums
            nums[idx] = val;
            // Recompute the popcount-depth for the updated value
            long long x = val;
            long long d = 0;
            while (x > 0) {
                x = __builtin_popcount(x);
                d++;
            }
            // Update the frequency array
            long long old_depth = popcount_depths[idx];
            freq[idx][old_depth]--;
            if (freq[idx][old_depth] == 0) {
                freq[idx][old_depth] = 0;
            }
            freq[idx][d]++;
            popcount_depths[idx] = d;
        }
    }

    return answer;
}
